# Utility functions for shape operations

from shapes import Shape, Circle

def scale_circle(circle: Circle, factor: float) -> Circle:
    new_radius: float = circle.radius * factor
    return Circle(circle.name, new_radius)

def total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for shape in shapes:
        total += shape.area()
    return total
